Add two helper methods on Cache:
  def _serialize_for_disk(self, value):
      payload = pickle.dumps(value)
      if self.compress == 'gzip':
          payload = gzip.compress(payload); codec = CODEC_GZIP
      elif self.compress == 'zlib':
          payload = zlib.compress(payload); codec = CODEC_ZLIB
      else:
          codec = CODEC_NONE
      return MAGIC + bytes([codec]) + payload

  def _deserialize_from_disk(self, raw):
      if isinstance(raw, (bytes, bytearray)) and bytes(raw[:4]) == MAGIC:
          codec = raw[4]; payload = bytes(raw[5:])
          if codec == CODEC_GZIP: payload = gzip.decompress(payload)
          elif codec == CODEC_ZLIB: payload = zlib.decompress(payload)
          return pickle.loads(payload)
      return raw  # legacy pre-feature entry (no header) - return as-is, backward compatible

  def set_compression(self, codec: Optional[str] = None):
      if codec not in (None, 'gzip', 'zlib'):
          raise ValueError(f'Unsupported compression codec: {codec}')
      self.compress = codec

